CREATE TABLE IF NOT EXISTS users ("name" VARCHAR(50) PRIMARY KEY, slack_id VARCHAR(12) NULL, follower_count INT NULL, following_count INT NULL, first_seen TIMESTAMP NOT NULL, last_requested TIMESTAMP NULL, last_requested_iteration INT NULL);
CREATE TABLE IF NOT EXISTS projects (id INT PRIMARY KEY, "owner" VARCHAR(50) NOT NULL, title VARCHAR(120) NULL, description VARCHAR(1000) NULL, "followerCount" INT NULL, "devlogCount" INT NULL, "totalHours" INT NULL, "firstSeen" TIMESTAMP NOT NULL, "lastRequested" TIMESTAMP NULL, last_requested_iteration INT NULL, CONSTRAINT fk_projects_owner__name FOREIGN KEY ("owner") REFERENCES users("name") ON DELETE RESTRICT ON UPDATE RESTRICT);